output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?hairstyle ?label(YEAR(?date) AS ?year) WHERE {
  ?hairstyle wdt:P31 wd:Q327496 .
  OPTIONAL {
    ?hairstyle wdt:P580 | wdt:P585 ?date
  }
  FILTER(YEAR(?date) >= 1900 && YEAR(?date) <= 1999)
  OPTIONAL {
    ?hairstyle rdfs:label ?label
    FILTER(LANG(?label) = 'en')
  }
}
ORDER BY ?year

args.sparql:
SELECT ?hairstyle ?hairstyleLabel ?year WHERE {
  ?hairstyle wdt:P31 wd:Q327496.
  ?hairstyle wdt:P580 ?startDate.
  BIND(YEAR(?startDate) AS ?year)
  FILTER(?year >= 1900 && ?year <= 1999)
  OPTIONAL { ?hairstyle rdfs:label ?hairstyleLabel FILTER(LANG(?hairstyleLabel) = "en") }
}
ORDER BY ?year
LIMIT 20

